std::vector<OSOCTET> hexStringToBytes(const std::string& hex) {
    std::vector<OSOCTET> bytes;
    for (size_t i = 0; i < hex.length(); i += 2) {
        std::string byteString = hex.substr(i, 2);
        OSOCTET byte = static_cast<OSOCTET>(strtol(byteString.c_str(), nullptr, 16));
        bytes.push_back(byte);
    }
    return bytes;
}


